INSERT INTO public.exception_report (created_at, id, reported_by, resolved_at, session_id, description, resolution_note, status, type) VALUES ('2026-06-30 12:57:33.516849+00', 1, 3, '2026-06-27 12:57:33.516855+00', 1, 'Driver lost paper ticket. Verified entry via CCTV at 08:15. Plate: 51F-123.45.', 'Confirmed via CCTV. Charged standard rate + lost ticket penalty.', 'RESOLVED', 'LOST_TICKET');
INSERT INTO public.exception_report (created_at, id, reported_by, resolved_at, session_id, description, resolution_note, status, type) VALUES ('2026-06-30 12:57:33.517363+00', 2, 3, '2026-06-28 12:57:33.517364+00', 2, 'Plate mismatch at exit: entry 51G-111.22, exit scan reads 51G-111.23. Likely OCR error.', 'Manual override. OCR misread ''2'' as ''3''. Visual match confirmed.', 'RESOLVED', 'WRONG_PLATE');
