INSERT INTO public.feedback (rating, created_at, id, session_id, user_id, comment) VALUES (5, '2026-06-30 12:57:33.518493+00', 1, 1, 9, 'Very convenient parking system. The auto-allocation saved me a lot of time!');
INSERT INTO public.feedback (rating, created_at, id, session_id, user_id, comment) VALUES (4, '2026-06-30 12:57:33.519131+00', 2, 29, 8, 'Staff was helpful when I had trouble with the check-out process.');
INSERT INTO public.feedback (rating, created_at, id, session_id, user_id, comment) VALUES (3, '2026-06-30 12:57:33.519335+00', 3, 57, 4, 'Good location but could use better lighting on Level 2.');
INSERT INTO public.feedback (rating, created_at, id, session_id, user_id, comment) VALUES (5, '2026-06-30 12:57:33.519578+00', 4, 85, 4, 'The online payment is super fast. Love the QR code feature!');
INSERT INTO public.feedback (rating, created_at, id, session_id, user_id, comment) VALUES (2, '2026-06-30 12:57:33.519772+00', 5, 113, 8, 'Waited too long for the gate to open. Needs improvement.');
INSERT INTO public.feedback (rating, created_at, id, session_id, user_id, comment) VALUES (5, '2026-06-30 12:57:33.519953+00', 6, 141, 7, 'Clean and well-organized parking building. Will come back!');
INSERT INTO public.feedback (rating, created_at, id, session_id, user_id, comment) VALUES (4, '2026-06-30 12:57:33.520101+00', 7, 169, 4, 'Price is reasonable for the area. Monthly pass is a great deal.');
INSERT INTO public.feedback (rating, created_at, id, session_id, user_id, comment) VALUES (5, '2026-06-30 12:57:33.520211+00', 8, 197, 5, 'The app is easy to use. Found my slot quickly with auto-allocation.');
INSERT INTO public.feedback (rating, created_at, id, session_id, user_id, comment) VALUES (3, '2026-06-30 12:57:33.520318+00', 9, 225, 8, 'Had an issue with wrong plate detection but staff resolved it fast.');
INSERT INTO public.feedback (rating, created_at, id, session_id, user_id, comment) VALUES (4, '2026-06-30 12:57:33.520427+00', 10, 253, 6, 'Great experience overall. The reservation feature is very useful.');
INSERT INTO public.feedback (rating, created_at, id, session_id, user_id, comment) VALUES (4, '2026-06-30 12:57:33.520533+00', 11, 281, 7, 'Parking space was a bit tight for my SUV.');
INSERT INTO public.feedback (rating, created_at, id, session_id, user_id, comment) VALUES (5, '2026-06-30 12:57:33.520624+00', 12, 309, 6, 'Excellent service! The EV charging bay is a nice touch.');
